import base64

# Manual content in Base64 to avoid terminal encoding issues
manual_b64 = ""

def recover():
    content = base64.b64decode(manual_b64).decode('utf-8')
    with open('SYSTEM_MANUAL.md', 'w', encoding='utf-8-sig') as f:
        f.write(content)
    print("RECOVERY SUCCESS: SYSTEM_MANUAL.md restored via Base64 literal.")

if __name__ == "__main__":
    recover()
